import { useRef, useState } from "react";

import base from "./pizza_base.png";

const toppings = ["🍄", "🧀", "🌽", "🍍", "🧅", "🌶️", "🫑"];

const toppingPrices = {
  "🍄": 40,
  "🧀": 45,
  "🌽": 30,
  "🍍": 35,
  "🧅": 20,
  "🌶️": 25,
  "🫑": 30,
};

const BASE_PRICE = 299;

export default function PizzaBuilder() {
  const [selected, setSelected] = useState(toppings[0]);
  const [pizza, setPizza] = useState([]);

  const imageRef = useRef(null);

  function handlePizzaClick(e) {
    const image = imageRef.current;
    const rect = image.getBoundingClientRect();

    // Convert from screen coordinates to the image's natural coordinates
    const x =
      ((e.clientX - rect.left) * image.naturalWidth) / rect.width;

    const y =
      ((e.clientY - rect.top) * image.naturalHeight) / rect.height;

    setPizza((pizza) => [
      ...pizza,
      {
        topping: selected,
        x,
        y,
      },
    ]);
  }

  function calculateTotal() {
    return pizza.reduce(
      (total, { topping }) => total + toppingPrices[topping],
      BASE_PRICE
    );
  }

  return (
    <main>
      <h1>🍕 Pizza Builder</h1>

      <h2>Total: ₹{calculateTotal()}</h2>

      <p>
        {toppings.map((topping) => (
          <button
            key={topping}
            onClick={() => setSelected(topping)}
            disabled={selected === topping}
          >
            {topping}
          </button>
        ))}
      </p>

      <figure
        style={{
          position: "relative",
          display: "inline-block",
          margin: 0,
        }}
      >
        <img
          ref={imageRef}
          src={base}
          alt="Pizza"
          onClick={handlePizzaClick}
          style={{
            width: 500,
            maxWidth: "100%",
            display: "block",
            cursor: "crosshair",
          }}
        />

        {pizza.map(({ topping, x, y }, index) => {
          const image = imageRef.current;

          if (!image) return null;

          const rect = image.getBoundingClientRect();

          // Convert back from natural coordinates to the current display size
          const left = (x / image.naturalWidth) * rect.width;
          const top = (y / image.naturalHeight) * rect.height;

          return (
            <span
              key={index}
              style={{
                position: "absolute",
                left,
                top,
                transform: "translate(-50%, -50%)",
                fontSize: "1.5rem",
                lineHeight: 1,
                pointerEvents: "none",
                userSelect: "none",
              }}
            >
              {topping}
            </span>
          );
        })}
      </figure>
    </main>
  );
}
